{ title: "Pedir en un café de Ammán", scene: "Estás en una cafetería pequeña cerca del centro de Ammán. Quieres pedir café, agua y algo sencillo para comer.", lines: [{ who: "them", ar: "مرحبا، ماذا تريد؟", es: "Hola, ¿qué quieres?" }, { who: "you", ar: "أريد قهوة من فضلك", es: "Quiero un café, por favor." }, { who: "them", ar: "هل تريد سكر؟", es: "¿Quieres azúcar?" }, { who: "you", ar: "لا، بدون سكر", es: "No, sin azúcar." }, { who: "them", ar: "هل تريد شيئا آخر؟", es: "¿Quieres algo más?" }, { who: "you", ar: "نعم، أريد ماء وخبز", es: "Sí, quiero agua y pan." }, { who: "them", ar: "الماء بارد أم عادي؟", es: "¿El agua fría o normal?" }, { who: "you", ar: "ماء بارد من فضلك", es: "Agua fría, por favor." }, { who: "them", ar: "تفضل، القهوة والماء", es: "Aquí tienes, el café y el agua." }, { who: "you", ar: "شكرا، كم السعر؟", es: "Gracias, ¿cuánto cuesta?" }, { who: "them", ar: "السعر أربعة دنانير", es: "El precio es cuatro dinares." }, { who: "you", ar: "تفضل، شكرا جزيلا", es: "Aquí tiene, muchas gracias." }] },
{ title: "Registrarse en un hotel de Beirut", scene: "Llegas a un hotel en Beirut por la tarde. Tienes una reserva y quieres confirmar si el desayuno está incluido.", lines: [{ who: "them", ar: "مساء الخير، أهلا وسهلا", es: "Buenas tardes, bienvenido." }, { who: "you", ar: "مساء الخير، لدي حجز", es: "Buenas tardes, tengo una reserva." }, { who: "them", ar: "ما اسمك؟", es: "¿Cuál es tu nombre?" }, { who: "you", ar: "اسمي كارلوس غارسيا", es: "Me llamo Carlos García." }, { who: "them", ar: "نعم، الحجز موجود", es: "Sí, la reserva está aquí." }, { who: "you", ar: "هل الإفطار مشمول؟", es: "¿El desayuno está incluido?" }, { who: "them", ar: "نعم، الإفطار من السابعة إلى العاشرة", es: "Sí, el desayuno es de siete a diez." }, { who: "you", ar: "ممتاز، أين المصعد؟", es: "Excelente, ¿dónde está el ascensor?" }, { who: "them", ar: "المصعد بجانب الاستقبال", es: "El ascensor está al lado de la recepción." }, { who: "you", ar: "أريد المفتاح من فضلك", es: "Quiero la llave, por favor." }, { who: "them", ar: "تفضل، الغرفة في الطابق الثالث", es: "Aquí tiene, la habitación está en el tercer piso." }, { who: "you", ar: "شكرا جزيلا", es: "Muchas gracias." }] },
{ title: "Preguntar direcciones en Marrakech", scene: "Estás caminando por la medina de Marrakech y buscas una plaza famosa. Te acercas a una persona local para pedir ayuda.", lines: [{ who: "you", ar: "مرحبا، أحتاج مساعدة من فضلك", es: "Hola, necesito ayuda, por favor." }, { who: "them", ar: "نعم، تفضل", es: "Sí, adelante." }, { who: "you", ar: "أين هذا الميدان؟", es: "¿Dónde está esta plaza?" }, { who: "them", ar: "امش مباشرة ثم يمين", es: "Camina recto y luego a la derecha." }, { who: "you", ar: "هل هو قريب؟", es: "¿Está cerca?" }, { who: "them", ar: "نعم، قريب جدا", es: "Sí, muy cerca." }, { who: "you", ar: "هل هو بجانب السوق؟", es: "¿Está al lado del mercado?" }, { who: "them", ar: "نعم، بجانب السوق الكبير", es: "Sí, al lado del mercado grande." }, { who: "you", ar: "قل ذلك مرة أخرى من فضلك", es: "Dígalo otra vez, por favor." }, { who: "them", ar: "مباشرة ثم يمين", es: "Recto y luego derecha." }, { who: "you", ar: "شكرا على المساعدة", es: "Gracias por la ayuda." }, { who: "them", ar: "لا مشكلة", es: "No hay problema." }] },
{ title: "Comer en un restaurante de Rabat", scene: "Entras en un restaurante de Rabat para cenar. Quieres una mesa para dos, preguntar por un plato local y pedir la cuenta.", lines: [{ who: "them", ar: "مرحبا، كم شخصا؟", es: "Hola, ¿cuántas personas?" }, { who: "you", ar: "طاولة لشخصين من فضلك", es: "Una mesa para dos, por favor." }, { who: "them", ar: "تفضل، هذه الطاولة", es: "Adelante, esta mesa." }, { who: "you", ar: "شكرا، ما الطبق المحلي؟", es: "Gracias, ¿cuál es el plato local?" }, { who: "them", ar: "لدينا دجاج مع أرز وخضار", es: "Tenemos pollo con arroz y verduras." }, { who: "you", ar: "ممتاز، أريد هذا الطبق", es: "Excelente, quiero ese plato." }, { who: "them", ar: "هل تريد ماء؟", es: "¿Quieres agua?" }, { who: "you", ar: "نعم، ماء بدون غاز", es: "Sí, agua sin gas." }, { who: "them", ar: "هل الطعام جيد؟", es: "¿La comida está buena?" }, { who: "you", ar: "نعم، الطعام لذيذ جدا", es: "Sí, la comida está muy deliciosa." }, { who: "them", ar: "هل تريد شيئا آخر؟", es: "¿Quieres algo más?" }, { who: "you", ar: "لا، الفاتورة من فضلك", es: "No, la cuenta, por favor." }] },
{ title: "Comprar billete de tren en Casablanca", scene: "Estás en una estación de Casablanca y quieres comprar un billete de tren. Necesitas saber el andén y la hora de salida.", lines: [{ who: "them", ar: "صباح الخير، إلى أين؟", es: "Buenos días, ¿a dónde?" }, { who: "you", ar: "أريد تذكرة قطار إلى الرباط", es: "Quiero un billete de tren a Rabat." }, { who: "them", ar: "ذهاب فقط أم ذهاب وعودة؟", es: "¿Solo ida o ida y vuelta?" }, { who: "you", ar: "ذهاب فقط من فضلك", es: "Solo ida, por favor." }, { who: "them", ar: "القطار يغادر في العاشرة", es: "El tren sale a las diez." }, { who: "you", ar: "كم السعر؟", es: "¿Cuánto cuesta?" }, { who: "them", ar: "السعر خمسون درهما", es: "El precio es cincuenta dírhams." }, { who: "you", ar: "هل تقبل البطاقة؟", es: "¿Acepta tarjeta?" }, { who: "them", ar: "نعم، نقبل البطاقة", es: "Sí, aceptamos tarjeta." }, { who: "you", ar: "أين الرصيف؟", es: "¿Dónde está el andén?" }, { who: "them", ar: "الرصيف رقم اثنين", es: "El andén número dos." }, { who: "you", ar: "شكرا، إلى اللقاء", es: "Gracias, hasta luego." }] },
{ title: "Comprar un regalo en un zoco de Fez", scene: "Estás mirando artesanías en un zoco de Fez. Quieres comprar un regalo, pero también negociar el precio con amabilidad.", lines: [{ who: "them", ar: "مرحبا، تفضل", es: "Hola, adelante." }, { who: "you", ar: "شكرا، أنا أنظر فقط", es: "Gracias, solo estoy mirando." }, { who: "them", ar: "هذا جميل جدا", es: "Esto es muy bonito." }, { who: "you", ar: "نعم، أريد شراء هدية", es: "Sí, quiero comprar un regalo." }, { who: "them", ar: "هذا مناسب جدا", es: "Esto es muy adecuado." }, { who: "you", ar: "كم ثمن هذا؟", es: "¿Cuánto cuesta esto?" }, { who: "them", ar: "الثمن مئة درهم", es: "El precio es cien dírhams." }, { who: "you", ar: "هل عندك سعر أفضل؟", es: "¿Tienes un mejor precio?" }, { who: "them", ar: "نعم، ثمانون درهما", es: "Sí, ochenta dírhams." }, { who: "you", ar: "جيد، هل تقبل البطاقة؟", es: "Bien, ¿aceptas tarjeta?" }, { who: "them", ar: "نعم، طبعا", es: "Sí, claro." }, { who: "you", ar: "ممتاز، سأشتريه", es: "Excelente, lo compraré." }] },
{ title: "En una farmacia de El Cairo", scene: "Estás en El Cairo y tienes dolor de cabeza. Entras en una farmacia para pedir ayuda y preguntar cómo tomar el medicamento.", lines: [{ who: "them", ar: "أهلا، كيف أساعدك؟", es: "Hola, ¿cómo puedo ayudarte?" }, { who: "you", ar: "لدي صداع", es: "Tengo dolor de cabeza." }, { who: "them", ar: "هل لديك حمى؟", es: "¿Tienes fiebre?" }, { who: "you", ar: "لا، ليس لدي حمى", es: "No, no tengo fiebre." }, { who: "them", ar: "هل تحتاج دواء؟", es: "¿Necesitas medicamento?" }, { who: "you", ar: "نعم، أحتاج دواء للصداع", es: "Sí, necesito medicamento para el dolor de cabeza." }, { who: "them", ar: "هل لديك حساسية؟", es: "¿Tienes alergia?" }, { who: "you", ar: "نعم، لدي حساسية بسيطة", es: "Sí, tengo una alergia leve." }, { who: "them", ar: "خذ هذا مع الماء", es: "Tome esto con agua." }, { who: "you", ar: "كم مرة في اليوم؟", es: "¿Cuántas veces al día?" }, { who: "them", ar: "مرتين في اليوم", es: "Dos veces al día." }, { who: "you", ar: "شكرا جزيلا", es: "Muchas gracias." }] },
{ title: "Charla amable con una persona local en Túnez", scene: "Estás sentado en una terraza en Túnez y una persona local inicia una conversación. Quieres responder de manera amable y practicar tu árabe básico.", lines: [{ who: "you", ar: "مرحبا، هل هذا المكان مفتوح؟", es: "Hola, ¿este lugar está abierto?" }, { who: "them", ar: "نعم، مفتوح، تفضل", es: "Sí, está abierto, adelante." }, { who: "you", ar: "شكرا، هذه المدينة جميلة", es: "Gracias, esta ciudad es hermosa." }, { who: "them", ar: "هل أنت سائح؟", es: "¿Eres turista?" }, { who: "you", ar: "نعم، أنا سائح من إسبانيا", es: "Sí, soy turista de España." }, { who: "them", ar: "هل تتكلم العربية؟", es: "¿Hablas árabe?" }, { who: "you", ar: "أتكلم العربية قليلا", es: "Hablo un poco de árabe." }, { who: "them", ar: "ممتاز، أهلا وسهلا", es: "Excelente, bienvenido." }, { who: "you", ar: "الناس هنا لطفاء جدا", es: "La gente aquí es muy amable." }, { who: "them", ar: "شكرا، هل تحب الطعام؟", es: "Gracias, ¿te gusta la comida?" }, { who: "you", ar: "نعم، أحب الطعام هنا كثيرا", es: "Sí, me gusta mucho la comida aquí." }, { who: "them", ar: "أتمنى لك رحلة جميلة", es: "Te deseo un viaje bonito." }] }
